Here is the result class I use. I tried to clean it up as much as I could (my experiment has a lot of other stuff in it), I hope I didn’t left anything important out. Just let me know if you need some clarification.

```python
class CoverageResult(unittest.result.TestResult):
    def __init__(self,
                 stream, destriptions, verbosity,
                 coverage_sources=None, **kwargs):
        self.verbosity = verbosity

        if coverage_sources:
            self.coverage = coverage.coverage(branch=True, include=coverage_sources)
        else:
            self.coverage = None

        self.test_data = {}

    def startTest(self, test):
        self.test_data[test] = {}

        if self.coverage:
            self.coverage.start()

        super(CoverageResult, self).startTest(test)

    def stopTest(self, test):
        super(CoverageResult, self).stopTest(test)

        if self.coverage:
            self.coverage.stop()
            self.test_data[test]['coverage'] = self.coverage.data
            self.coverage.data = coverage.CoverageData()

            if self.verbosity > 2:
                self.coverage.report()

            self.coverage.erase()

        # This is needed so I don’t erase the result I just saved
        self.coverage.erase()

    @property
    def coverage_data(self):
        for test, data in self.test_data:
            self.coverage.data.update(d['coverage'])

        return self.coverage
```

