import graphene
import inspect

class ListType(graphene.List):
    def __init__(self, *args, **kwargs):
        try:
            of_type = [item for item in inspect.getmembers(self.__class__)
                       if item[0] == 'child'][0][1]
        except IndexError:
            raise AttributeError('Class must have an attribute with name child')
        super(ListType, self).__init__(of_type=of_type, *args, **kwargs)

class AList(graphene.ListType):
